import{_ as i,o as s,c as t,ai as o}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"TUI","description":"","frontmatter":{"summary":"Terminal UI (TUI): connect to the Gateway from any machine","read_when":["You want a beginner-friendly walkthrough of the TUI","You need the complete list of TUI features, commands, and shortcuts"],"title":"TUI"},"headers":[],"relativePath":"web/tui.md","filePath":"web/tui.md","lastUpdated":1771906665000}'),l={name:"web/tui.md"};function a(n,e,d,r,c,h){return s(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="tui-terminal-ui" tabindex="-1"><a class="header-anchor" href="#tui-terminal-ui">#</a> TUI (Terminal UI)</h1><h2 id="quick-start" tabindex="-1"><a class="header-anchor" href="#quick-start">#</a> Quick start</h2><ol><li>Start the Gateway.</li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="2"><li>Open the TUI.</li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tui</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="3"><li>Type a message and press Enter.</li></ol><p>Remote Gateway:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tui</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ws://</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">hos</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">por</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --token</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gateway-toke</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Use <code>--password</code> if your Gateway uses password auth.</p><h2 id="what-you-see" tabindex="-1"><a class="header-anchor" href="#what-you-see">#</a> What you see</h2><ul><li>Header: connection URL, current agent, current session.</li><li>Chat log: user messages, assistant replies, system notices, tool cards.</li><li>Status line: connection/run state (connecting, running, streaming, idle, error).</li><li>Footer: connection state + agent + session + model + think/verbose/reasoning + token counts + deliver.</li><li>Input: text editor with autocomplete.</li></ul><h2 id="mental-model-agents-sessions" tabindex="-1"><a class="header-anchor" href="#mental-model-agents-sessions">#</a> Mental model: agents + sessions</h2><ul><li>Agents are unique slugs (e.g. <code>main</code>, <code>research</code>). The Gateway exposes the list.</li><li>Sessions belong to the current agent.</li><li>Session keys are stored as <code>agent:&lt;agentId&gt;:&lt;sessionKey&gt;</code>. <ul><li>If you type <code>/session main</code>, the TUI expands it to <code>agent:&lt;currentAgent&gt;:main</code>.</li><li>If you type <code>/session agent:other:main</code>, you switch to that agent session explicitly.</li></ul></li><li>Session scope: <ul><li><code>per-sender</code> (default): each agent has many sessions.</li><li><code>global</code>: the TUI always uses the <code>global</code> session (the picker may be empty).</li></ul></li><li>The current agent + session are always visible in the footer.</li></ul><h2 id="sending-delivery" tabindex="-1"><a class="header-anchor" href="#sending-delivery">#</a> Sending + delivery</h2><ul><li>Messages are sent to the Gateway; delivery to providers is off by default.</li><li>Turn delivery on: <ul><li><code>/deliver on</code></li><li>or the Settings panel</li><li>or start with <code>opensoul tui --deliver</code></li></ul></li></ul><h2 id="pickers-overlays" tabindex="-1"><a class="header-anchor" href="#pickers-overlays">#</a> Pickers + overlays</h2><ul><li>Model picker: list available models and set the session override.</li><li>Agent picker: choose a different agent.</li><li>Session picker: shows only sessions for the current agent.</li><li>Settings: toggle deliver, tool output expansion, and thinking visibility.</li></ul><h2 id="keyboard-shortcuts" tabindex="-1"><a class="header-anchor" href="#keyboard-shortcuts">#</a> Keyboard shortcuts</h2><ul><li>Enter: send message</li><li>Esc: abort active run</li><li>Ctrl+C: clear input (press twice to exit)</li><li>Ctrl+D: exit</li><li>Ctrl+L: model picker</li><li>Ctrl+G: agent picker</li><li>Ctrl+P: session picker</li><li>Ctrl+O: toggle tool output expansion</li><li>Ctrl+T: toggle thinking visibility (reloads history)</li></ul><h2 id="slash-commands" tabindex="-1"><a class="header-anchor" href="#slash-commands">#</a> Slash commands</h2><p>Core:</p><ul><li><code>/help</code></li><li><code>/status</code></li><li><code>/agent &lt;id&gt;</code> (or <code>/agents</code>)</li><li><code>/session &lt;key&gt;</code> (or <code>/sessions</code>)</li><li><code>/model &lt;provider/model&gt;</code> (or <code>/models</code>)</li></ul><p>Session controls:</p><ul><li><code>/think &lt;off|minimal|low|medium|high&gt;</code></li><li><code>/verbose &lt;on|full|off&gt;</code></li><li><code>/reasoning &lt;on|off|stream&gt;</code></li><li><code>/usage &lt;off|tokens|full&gt;</code></li><li><code>/elevated &lt;on|off|ask|full&gt;</code> (alias: <code>/elev</code>)</li><li><code>/activation &lt;mention|always&gt;</code></li><li><code>/deliver &lt;on|off&gt;</code></li></ul><p>Session lifecycle:</p><ul><li><code>/new</code> or <code>/reset</code> (reset the session)</li><li><code>/abort</code> (abort the active run)</li><li><code>/settings</code></li><li><code>/exit</code></li></ul><p>Other Gateway slash commands (for example, <code>/context</code>) are forwarded to the Gateway and shown as system output. See <a href="/docs/tools/slash-commands">Slash commands</a>.</p><h2 id="local-shell-commands" tabindex="-1"><a class="header-anchor" href="#local-shell-commands">#</a> Local shell commands</h2><ul><li>Prefix a line with <code>!</code> to run a local shell command on the TUI host.</li><li>The TUI prompts once per session to allow local execution; declining keeps <code>!</code> disabled for the session.</li><li>Commands run in a fresh, non-interactive shell in the TUI working directory (no persistent <code>cd</code>/env).</li><li>A lone <code>!</code> is sent as a normal message; leading spaces do not trigger local exec.</li></ul><h2 id="tool-output" tabindex="-1"><a class="header-anchor" href="#tool-output">#</a> Tool output</h2><ul><li>Tool calls show as cards with args + results.</li><li>Ctrl+O toggles between collapsed/expanded views.</li><li>While tools run, partial updates stream into the same card.</li></ul><h2 id="history-streaming" tabindex="-1"><a class="header-anchor" href="#history-streaming">#</a> History + streaming</h2><ul><li>On connect, the TUI loads the latest history (default 200 messages).</li><li>Streaming responses update in place until finalized.</li><li>The TUI also listens to agent tool events for richer tool cards.</li></ul><h2 id="connection-details" tabindex="-1"><a class="header-anchor" href="#connection-details">#</a> Connection details</h2><ul><li>The TUI registers with the Gateway as <code>mode: &quot;tui&quot;</code>.</li><li>Reconnects show a system message; event gaps are surfaced in the log.</li></ul><h2 id="options" tabindex="-1"><a class="header-anchor" href="#options">#</a> Options</h2><ul><li><code>--url &lt;url&gt;</code>: Gateway WebSocket URL (defaults to config or <code>ws://127.0.0.1:&lt;port&gt;</code>)</li><li><code>--token &lt;token&gt;</code>: Gateway token (if required)</li><li><code>--password &lt;password&gt;</code>: Gateway password (if required)</li><li><code>--session &lt;key&gt;</code>: Session key (default: <code>main</code>, or <code>global</code> when scope is global)</li><li><code>--deliver</code>: Deliver assistant replies to the provider (default off)</li><li><code>--thinking &lt;level&gt;</code>: Override thinking level for sends</li><li><code>--timeout-ms &lt;ms&gt;</code>: Agent timeout in ms (defaults to <code>agents.defaults.timeoutSeconds</code>)</li></ul><p>Note: when you set <code>--url</code>, the TUI does not fall back to config or environment credentials. Pass <code>--token</code> or <code>--password</code> explicitly. Missing explicit credentials is an error.</p><h2 id="troubleshooting" tabindex="-1"><a class="header-anchor" href="#troubleshooting">#</a> Troubleshooting</h2><p>No output after sending a message:</p><ul><li>Run <code>/status</code> in the TUI to confirm the Gateway is connected and idle/busy.</li><li>Check the Gateway logs: <code>opensoul logs --follow</code>.</li><li>Confirm the agent can run: <code>opensoul status</code> and <code>opensoul models status</code>.</li><li>If you expect messages in a chat channel, enable delivery (<code>/deliver on</code> or <code>--deliver</code>).</li><li><code>--history-limit &lt;n&gt;</code>: History entries to load (default 200)</li></ul><h2 id="connection-troubleshooting" tabindex="-1"><a class="header-anchor" href="#connection-troubleshooting">#</a> Connection troubleshooting</h2><ul><li><code>disconnected</code>: ensure the Gateway is running and your <code>--url/--token/--password</code> are correct.</li><li>No agents in picker: check <code>opensoul agents list</code> and your routing config.</li><li>Empty session picker: you might be in global scope or have no sessions yet.</li></ul>',44)])])}const g=i(l,[["render",a]]);export{u as __pageData,g as default};
